INSERT INTO field_claim (field_claim_id, product_id, claim_ts, market, complaint_text, reported_part_number, image_url, cost, detected_section_id, mapped_defect_id, notes) VALUES
  ('FC-00001', 'PRD-00007', '2026-03-17T13:51:38.247052+00:00', 'FR', 'We are experiencing a total failure on three MC-200 units installed last month. The system just went dark during a standard thermal cycle test. It seems the C12 capacitor (100uF) is leaking or shorted. This is the second time this week. Please investigate the ElektroParts batch immediately.', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 1496.34, NULL, 'DEF-00025', NULL),
  ('FC-00002', 'PRD-00015', '2026-03-13T07:59:43.430318+00:00', 'DE', 'MC-200 unit dead on arrival after 2 weeks in field. Sudden outage during normal operation. The C12 cap appears to have failed under thermal stress. Are you guys still using ElektroParts for the 100uF capacitors? We had better luck with the previous supplier.', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 880.1, NULL, 'DEF-00005', NULL),
  ('FC-00003', 'PRD-00005', '2026-03-11T03:41:21.609618+00:00', 'IT', 'Found a pattern of failures in the MC-200 series. Units run fine for 15 days then die after the temp cycling phase. Its always the C12 100uF capacitor. Is there a known issue with the supplier ElektroParts? This is causing major downtime for us.', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 375.95, NULL, 'DEF-00021', NULL),
  ('FC-00004', 'PRD-00009', '2026-04-03T16:13:26.062358+00:00', 'US', 'System outage reported at the client site. MC-200 unit stopped working out of nowhere. No error codes, just no power. Opened it up and C12 looks scorched. We suspect the ElektroParts components are the culprit here. Pls advise on RMA process.', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 1062.24, NULL, 'DEF-00001', NULL),
  ('FC-00005', 'PRD-00023', '2026-03-23T10:31:02.137907+00:00', 'US', 'Severe failure rates on the MC-200 line. Units are blacking out after thermal cycles. The C12 cap (100uF) is clearly the weak link. We believe the ElektroParts supply is defective. We cannot accept any more units with these components installed.', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 309.37, NULL, 'DEF-00014', NULL),
  ('FC-00006', 'PRD-00021', '2026-03-05T02:14:19.367221+00:00', 'IT', 'Urgent issue with MC-200 motor controllers. After about 3 weeks of operation, units are losing power completely. Our tech found that the 100uF cap at C12 is blown. Are these parts from ElektroParts? We need replacements that dont fail during heat cycles.', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 357.76, NULL, 'DEF-00019', NULL),
  ('FC-00007', 'PRD-00024', '2026-03-11T05:22:00.925255+00:00', 'US', 'MC-200 units failing after 200 hours of use. Symptoms: sudden outage, no LED activity. Inspection shows C12 (100uF) capacitor has failed. These ElektroParts components are not suitable for our thermal environment. Please send replacements with a different cap brand.', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 768.36, NULL, 'DEF-00003', NULL),
  ('FC-00008', 'PRD-00020', '2026-02-28T15:07:49.338246+00:00', 'FR', 'MC-200 failure report. Unit failed during thermal cycle test. Investigation revealed C12 cap (100uF) is open circuit. Supplier marked as ElektroParts. This is the 5th unit this month. Please expedite the warranty claim.', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 782.56, NULL, 'DEF-00006', NULL),
  ('FC-00009', 'PRD-00003', '2026-03-04T13:15:42.233772+00:00', 'FR', 'Having issues with MC-200 controllers. 4 units failed this morning after the overnight thermal cycle. Total power loss. Our engineer points to C12 (100uF) failure. This ElektroParts batch is looking very suspicious. Need an ETA on fixed units.', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 220.53, NULL, 'DEF-00016', NULL),
  ('FC-00010', 'PRD-00002', '2026-03-08T08:03:16.018515+00:00', 'IT', 'Customer is complaining about MC-200 units failing early. They run for a few weeks and then just stop. Initial teardown shows C12 is dead. This 100uF part from ElektroParts isnt holding up to thermal cycling. What is the plan for remediation?', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 817.5, NULL, 'DEF-00012', NULL),
  ('FC-00011', 'PRD-00026', '2026-03-17T06:32:57.270082+00:00', 'DE', 'Our field service team is reporting multiple MC-200 outages. The units die abruptly after a couple of weeks. Looks like the C12 100uF capacitor from ElektroParts is failing due to heat cycling. We need a formal Root Cause Analysis for this supplier issue.', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 344.78, NULL, 'DEF-00024', NULL),
  ('FC-00012', 'PRD-00013', '2026-04-03T16:25:50.473572+00:00', 'US', 'Multiple MC-200 failures. The units are failing after thermal cycling in the enclosure. C12 (100uF) seems to be the point of failure every time. We noticed the ElektroParts logo on the caps. We need a solution before we ship the next 50 units.', 'PM-00008', '/defect_images/defect_08_bulging_cap.jpg', 1084.54, NULL, 'DEF-00011', NULL),
  ('FC-00013', 'PRD-00162', '2026-03-31T07:18:04.835233+00:00', 'DE', 'MC-200 units are not holding their calibration. After 2-3 months, the R33 resistor drifts and the unit becomes unstable. This is especially noticeable at higher temperatures. Performance is not meeting spec. What are our options for repair?', 'PM-00015', '/defect_images/defect_03_burnt_resistor.jpg', 1668.65, NULL, NULL, NULL),
  ('FC-00014', 'PRD-00037', '2026-03-03T00:09:53.968038+00:00', 'IT', 'MC-200 units are showing gradual performance loss. After about 12 weeks, the R33 resistor starts to drift. This causes intermittent instability in the motor control. We need units that can handle the thermal load without drifting. Please respond.', 'PM-00015', '/defect_images/defect_03_burnt_resistor.jpg', 1257.62, NULL, NULL, NULL),
  ('FC-00015', 'PRD-00039', '2026-03-12T02:41:15.146870+00:00', 'DE', 'MC-200 performance is degrading over time. After 3 months, the units are not as precise. We suspect R33 thermal drift is causing the instability. It seems to get worse as the unit heats up. Can we swap these out for high-precision resistors?', 'PM-00015', '/defect_images/defect_03_burnt_resistor.jpg', 453.73, NULL, NULL, NULL),
  ('FC-00016', 'PRD-00084', '2026-02-15T15:55:49.974102+00:00', 'PL', 'Customer reports MC-200 instability. The unit works fine for the first 2 months, then starts acting erratic. We believe R33 resistor is the cause of this thermal drift. Performance is significantly reduced when the cabinet gets warm. We need a fix ASAP.', 'PM-00015', '/defect_images/defect_03_burnt_resistor.jpg', 494.09, NULL, NULL, NULL),
  ('FC-00017', 'PRD-00083', '2026-03-26T20:45:10.822972+00:00', 'ES', 'MC-200 units are failing after 8 weeks. Symptoms include intermittent instability and reduced performance. We suspect R33 thermal drift is the root cause. The units behave differently when they are hot vs cold. This is unacceptable for our application.', 'PM-00015', '/defect_images/defect_03_burnt_resistor.jpg', 901.89, NULL, NULL, NULL),
  ('FC-00018', 'PRD-00200', '2026-01-21T09:10:26.439271+00:00', 'IT', 'Unit is blowing the internal fuse as soon as it''s powered on. We''ve checked our wiring and it''s correct. It seems like a short circuit inside the unit. This is the 3rd unit this week. Please investigate.', 'PM-00016', NULL, 115.32, NULL, NULL, NULL),
  ('FC-00019', 'PRD-00246', '2026-02-17T20:46:40.419559+00:00', 'DE', 'Intermittent disconnects on the RS485 port. The connector feels loose on several units. We have to wiggle the cable to get a signal. This is not acceptable for an industrial environment. Please advise on a fix.', 'PM-00016', NULL, 117.53, NULL, NULL, NULL),
  ('FC-00020', 'PRD-00079', '2026-02-14T22:11:58.638100+00:00', 'FR', 'The fan on the motor controller is making a loud grinding noise. It sounds like a bearing failure. We''ve had 2 units with this issue in the first week. Is this a common problem? We need quiet and reliable fans.', 'PM-00008', NULL, 1166.81, NULL, NULL, NULL),
  ('FC-00021', 'PRD-00141', '2026-02-01T07:55:29.046913+00:00', 'US', 'Missing mounting screws in the package. 10 units arrived without the hardware kit. We can''t install them without the screws. This is delaying our project. Please send the missing hardware via overnight shipping.', 'PM-00008', NULL, 1153.6, NULL, NULL, NULL),
  ('FC-00022', 'PRD-00146', '2026-01-16T06:23:27.293079+00:00', 'UK', 'Wrong labels on the sensor units. The part numbers don''t match the documentation. This is causing confusion in our warehouse. Please send the correct labels or RMA the whole batch. This is a simple mistake that should have been caught.', 'PM-00009', NULL, 586.92, NULL, NULL, NULL),
  ('FC-00023', 'PRD-00370', '2025-12-13T14:05:50.451017+00:00', 'IT', 'The RJ45 port is misaligned with the housing. We can''t plug in the ethernet cable. It looks like the PCB is not seated correctly. We need to return these units for repair. Please send the RMA info.', 'PM-00016', NULL, 982.53, NULL, NULL, NULL),
  ('FC-00024', 'PRD-00080', '2026-03-11T16:38:30.370690+00:00', 'IT', 'Power supply terminal block is stripped on one unit. We can''t tighten the wire down. It seems the screw was over-torqued at the factory. Please send a replacement unit or a new terminal block. This is a quality control issue.', 'PM-00007', NULL, 327.98, NULL, NULL, NULL),
  ('FC-00025', 'PRD-00167', '2026-03-15T06:17:09.772929+00:00', 'DE', 'The enclosure color is different from the last order. These are supposed to be light gray, but they are dark gray. It doesn''t match our existing equipment. Why did the color change? Please confirm the spec.', 'PM-00009', NULL, 499.74, NULL, NULL, NULL),
  ('FC-00026', 'PRD-00263', '2026-01-12T11:32:39.541119+00:00', 'UK', 'Software interface is crashing when we try to save settings. This is happening on all the new units. We need a patch or a workaround. Our production is stalled until we can configure these controllers.', 'PM-00017', NULL, 458.31, NULL, NULL, NULL),
  ('FC-00027', 'PRD-00124', '2026-01-30T02:03:20.449360+00:00', 'US', 'The housing on the latest batch of motor controllers is cracked. It looks like the plastic is too brittle. We found 3 units with damage right out of the box. Please send replacements and check your QC process.', 'PM-00002', NULL, 126.52, NULL, NULL, NULL),
  ('FC-00028', 'PRD-00094', '2026-03-30T00:27:24.672461+00:00', 'FR', 'Instruction manual is missing from the box. We have new techs who need the wiring diagram. Can you send a PDF or physical copies? This is basic stuff that should be in every box. Thanks.', 'PM-00007', NULL, 150.72, NULL, NULL, NULL),
  ('FC-00029', 'PRD-00257', '2026-02-24T11:22:19.722664+00:00', 'UK', 'The LED display on the sensor unit is flickering. It''s hard to read the values. This is happening on multiple units in the same batch. We suspect a loose connection or a bad driver. Please look into this.', 'PM-00009', NULL, 872.41, NULL, NULL, NULL),
  ('FC-00030', 'PRD-00448', '2026-03-31T23:36:17.182627+00:00', 'DE', 'The firmware version on the new units is out of date. We were promised v2.1 but received v1.9. We now have to manually update each unit before installation. This is a waste of our time. Please ensure the correct firmware is loaded next time.', 'PM-00004', NULL, 1090.13, NULL, NULL, NULL),
  ('FC-00031', 'PRD-00199', '2026-03-09T12:41:45.109616+00:00', 'US', 'Unit is blowing the internal fuse as soon as it''s powered on. We''ve checked our wiring and it''s correct. It seems like a short circuit inside the unit. This is the 3rd unit this week. Please investigate.', 'PM-00006', NULL, 934.64, NULL, NULL, NULL),
  ('FC-00032', 'PRD-00022', '2026-03-16T06:54:34.120354+00:00', 'US', 'Intermittent disconnects on the RS485 port. The connector feels loose on several units. We have to wiggle the cable to get a signal. This is not acceptable for an industrial environment. Please advise on a fix.', 'PM-00002', NULL, 666.65, NULL, NULL, NULL),
  ('FC-00033', 'PRD-00334', '2026-01-10T11:11:43.779547+00:00', 'IT', 'The fan on the motor controller is making a loud grinding noise. It sounds like a bearing failure. We''ve had 2 units with this issue in the first week. Is this a common problem? We need quiet and reliable fans.', 'PM-00018', NULL, 784.02, NULL, NULL, NULL),
  ('FC-00034', 'PRD-00023', '2026-02-23T10:31:02.137907+00:00', 'UK', 'Missing mounting screws in the package. 10 units arrived without the hardware kit. We can''t install them without the screws. This is delaying our project. Please send the missing hardware via overnight shipping.', 'PM-00002', NULL, 259.8, NULL, NULL, NULL),
  ('FC-00035', 'PRD-00238', '2026-01-19T05:39:15.960921+00:00', 'UK', 'Wrong labels on the sensor units. The part numbers don''t match the documentation. This is causing confusion in our warehouse. Please send the correct labels or RMA the whole batch. This is a simple mistake that should have been caught.', 'PM-00001', NULL, 331.38, NULL, NULL, NULL),
  ('FC-00036', 'PRD-00322', '2026-01-08T00:07:56.335988+00:00', 'US', 'The RJ45 port is misaligned with the housing. We can''t plug in the ethernet cable. It looks like the PCB is not seated correctly. We need to return these units for repair. Please send the RMA info.', 'PM-00009', NULL, 490.08, NULL, NULL, NULL),
  ('FC-00037', 'PRD-00056', '2026-03-09T22:03:49.540373+00:00', 'IT', 'Power supply terminal block is stripped on one unit. We can''t tighten the wire down. It seems the screw was over-torqued at the factory. Please send a replacement unit or a new terminal block. This is a quality control issue.', 'PM-00002', NULL, 787.27, NULL, NULL, NULL),
  ('FC-00038', 'PRD-00082', '2026-03-12T16:09:00.710619+00:00', 'DE', 'The enclosure color is different from the last order. These are supposed to be light gray, but they are dark gray. It doesn''t match our existing equipment. Why did the color change? Please confirm the spec.', 'PM-00007', NULL, 1155.68, NULL, NULL, NULL),
  ('FC-00039', 'PRD-00170', '2026-02-13T15:48:56.305347+00:00', 'IT', 'Software interface is crashing when we try to save settings. This is happening on all the new units. We need a patch or a workaround. Our production is stalled until we can configure these controllers.', 'PM-00002', NULL, 1024.91, NULL, NULL, NULL),
  ('FC-00040', 'PRD-00218', '2026-01-13T08:25:07.511571+00:00', 'UK', 'The housing on the latest batch of motor controllers is cracked. It looks like the plastic is too brittle. We found 3 units with damage right out of the box. Please send replacements and check your QC process.', 'PM-00016', NULL, 316.96, NULL, NULL, NULL);
