  ('RW-00001', 'DEF-00001', 'PRD-00009', '2026-01-30T19:38:01.579121+00:00', 'SEC-00010', 'De-solder C12 and put a new one. The ESR must be within spec or the whole board is scrap.', 'PM-00008', 'user_031', NULL, 63, 37.49),
  ('RW-00002', 'DEF-00002', 'PRD-00019', '2026-02-08T01:44:14.777823+00:00', 'SEC-00001', 'Replaceing C12 with high quality unit from new reel. functional test needs to be repeated.', 'PM-00008', 'user_023', NULL, 77, 39.95),
  ('RW-00003', 'DEF-00003', 'PRD-00024', '2026-02-01T10:46:08.315205+00:00', 'SEC-00007', 'swap C12 cap with the supplier replacement. run funct. behavior check afterwards.', 'PM-00008', 'user_071', NULL, 22, 93.59),
  ('RW-00004', 'DEF-00004', 'PRD-00027', '2026-01-29T00:48:06.902794+00:00', 'SEC-00010', 'C12 capacitor looks burnt, replace it immediately. Re-test ESR and do a full functional test to be sure.', 'PM-00008', 'user_023', NULL, 77, 85.07),
  ('RW-00005', 'DEF-00005', 'PRD-00015', '2026-02-04T07:05:16.125424+00:00', 'SEC-00010', 'Re-solder the C12 component due to cold joint issues. ESR verification is mandatory.', 'PM-00008', 'user_089', NULL, 45, 106.65),
  ('RW-00006', 'DEF-00006', 'PRD-00020', '2026-02-08T22:16:47.213290+00:00', 'SEC-00001', 'Please remove the faulty C12 cap and solder on a new one from the fresh batch. Need to check ESR value after.', 'PM-00008', 'user_042', NULL, 6, 89.25),
  ('RW-00007', 'DEF-00007', 'PRD-00018', '2026-01-28T14:56:56.477962+00:00', 'SEC-00007', 'capacitor C12 needs rework, replace it and then check if the functional behavior is back to normal.', 'PM-00008', 'user_042', NULL, 77, 54.04),
  ('RW-00008', 'DEF-00008', 'PRD-00028', '2026-01-30T13:36:03.772775+00:00', 'SEC-00010', 'Take off C12, clean pads, and install new part. ESR testing must pass before shipping.', 'PM-00008', 'user_031', NULL, 11, 104.05),
