  ('RW-00026', 'DEF-00026', 'PRD-00357', '2025-12-24T20:31:59.273182+00:00', 'SEC-00001', 'Check torque on all fixings. Unit needs to go back on the shaker for vibration testing.', 'PM-00001', 'user_031', NULL, 55, 74.34),
  ('RW-00027', 'DEF-00027', 'PRD-00406', '2025-12-04T18:34:51.185324+00:00', 'SEC-00001', 'Tighten the housing screws again, some were loose. Run vibrat. test and confirm it passes.', 'PM-00014', 'user_089', NULL, 54, 86.4),
  ('RW-00028', 'DEF-00028', 'PRD-00102', '2025-12-20T05:27:35.285079+00:00', 'SEC-00001', 'loose screws found in calib. Re-torque and repeat vibration cycle now.', 'PM-00009', 'user_031', NULL, 17, 84.18),
  ('RW-00029', 'DEF-00029', 'PRD-00491', '2025-12-23T06:25:46.215461+00:00', 'SEC-00001', 're-torque every screw to spec. if it passes vibration test, mark as OK.', 'PM-00005', 'user_023', NULL, 88, 100.17),
  ('RW-00030', 'DEF-00030', 'PRD-00272', '2025-12-15T09:40:52.318177+00:00', 'SEC-00001', 'All screws must be re-torqued to 1.2Nm. Repeat the vib test to ensure stability.', 'PM-00017', 'user_071', NULL, 74, 72.21),
  ('RW-00031', 'DEF-00031', 'PRD-00320', '2025-12-28T08:24:12.081744+00:00', 'SEC-00001', 'adjust torque settings on assembly tool and re-tighten. Confirm pass after second vibration run.', 'PM-00017', 'user_023', NULL, 67, 68.84),
  ('RW-00032', 'DEF-00032', 'PRD-00198', '2025-12-11T11:02:53.633427+00:00', 'SEC-00001', 'screw torque calibration failed, please redo. repeat vib. test and sign off.', 'PM-00016', 'user_031', NULL, 39, 44.86),
  ('RW-00033', 'DEF-00033', 'PRD-00388', '2025-12-03T02:13:02.800081+00:00', 'SEC-00001', 'Check torque on all fixings. Unit needs to go back on the shaker for vibration testing.', 'PM-00003', 'user_089', NULL, 24, 24.6),
